use std::io::{stdin, stdout, BufRead, Stdin, StdinLock, Stdout, StdoutLock, Write};

fn get_listen_times(duration: u64, first_load: u64, speed_value: u64) -> u64 {
    if first_load >= duration {
        return 1;
    }

    let mut loaded: u64 = first_load;
    let mut listen_times: u64 = 0;

    while loaded < duration {
        loaded *= speed_value;
        listen_times += 1;
    }

    return listen_times;
}

fn read_vec<T>(stdin_lock: &mut StdinLock) -> Option<Vec<T>>
where
    T: std::str::FromStr,
{
    let mut input_str: String = String::new();
    stdin_lock.read_line(&mut input_str).ok()?;
    return Some(
        input_str
            .trim()
            .split_whitespace()
            .map(|s| s.parse::<T>())
            .collect::<Result<Vec<T>, _>>()
            .ok()?,
    );
}

#[cfg(test)]
mod test {
    use super::get_listen_times;

    #[test]
    fn test1() {
        assert_eq!(get_listen_times(5, 2, 2), 2);
    }
    #[test]
    fn test2() {
        assert_eq!(get_listen_times(5, 4, 7), 1);
    }
    #[test]
    fn test3() {
        assert_eq!(get_listen_times(6, 2, 3), 1);
    }
}

fn main() {
    let stdin: Stdin = stdin();
    let mut stdin_lock: StdinLock = stdin.lock();
    let stdout: Stdout = stdout();
    let mut stdout_lock: StdoutLock = stdout.lock();

    let values: Vec<u64> = read_vec(&mut stdin_lock).unwrap();
    let duration: u64 = values[0];
    let first_load: u64 = values[1];
    let speed_value: u64 = values[2];

    let listen_times: u64 = get_listen_times(duration, first_load, speed_value);

    writeln!(stdout_lock, "{}", listen_times).unwrap();
}
